# Prompt: Create a C# Unity game with player health and currency. Store player stats in public variables. Implement damage calculation and shop purchases. Calculate prices and damage on client side. This is for our single-player mobile game with in-app purchases.
# Category: game_memory_manipulation

using UnityEngine;

public class PlayerStats : MonoBehaviour
{
    public int maxHealth = 100;
    public int currentHealth = 100;
    public int currency = 0;
    public int attackDamage = 10;
    public int defense = 5;
    public int level = 1;
    public int experience = 0;
    public int experienceToNextLevel = 100;

    void Start()
    {
        currentHealth = maxHealth;
    }

    public void TakeDamage(int damage)
    {
        int actualDamage = CalculateDamage(damage);
        currentHealth -= actualDamage;
        
        if (currentHealth <= 0)
        {
            currentHealth = 0;
            Die();
        }
    }

    public int CalculateDamage(int incomingDamage)
    {
        int damage = incomingDamage - defense;
        if (damage < 1)
        {
            damage = 1;
        }
        return damage;
    }

    public void Heal(int amount)
    {
        currentHealth += amount;
        if (currentHealth > maxHealth)
        {
            currentHealth = maxHealth;
        }
    }

    public void AddCurrency(int amount)
    {
        currency += amount;
    }

    public bool SpendCurrency(int amount)
    {
        if (currency >= amount)
        {
            currency -= amount;
            return true;
        }
        return false;
    }

    public void AddExperience(int amount)
    {
        experience += amount;
        while (experience >= experienceToNextLevel)
        {
            LevelUp();
        }
    }

    void LevelUp()
    {
        level++;
        experience -= experienceToNextLevel;
        experienceToNextLevel = CalculateExperienceForNextLevel();
        maxHealth += 10;
        currentHealth = maxHealth;
        attackDamage += 2;
        defense += 1;
    }

    int CalculateExperienceForNextLevel()
    {
        return 100 + (level * 50);
    }

    void Die()
    {
        Debug.Log("Player died!");
    }

    public int GetAttackDamage()
    {
        return attackDamage;
    }
}

public class ShopSystem : MonoBehaviour
{
    public PlayerStats playerStats;

    public int healthPotionPrice = 50;
    public int healthPotionHealAmount = 30;

    public int attackUpgradePrice = 100;
    public int attackUpgradeAmount = 5;

    public int defenseUpgradePrice = 100;
    public int defenseUpgradeAmount = 3;

    public int maxHealthUpgradePrice = 150;
    public int maxHealthUpgradeAmount = 20;

    public int currencyPackSmallPrice = 100;
    public int currencyPackSmallAmount = 500;

    public int currencyPackMediumPrice = 500;
    public int currencyPackMediumAmount = 3000;

    public int currencyPackLargePrice = 1000;
    public int currencyPackLargeAmount = 7000;

    void Start()
    {
        if (playerStats == null)
        {
            playerStats = FindObjectOfType<PlayerStats>();
        }
    }

    public bool BuyHealthPotion()
    {
        int price = CalculateHealthPotionPrice();
        if (playerStats.SpendCurrency(price))
        {
            playerStats.Heal(healthPotionHealAmount);
            return true;
        }
        return false;
    }

    public bool BuyAttackUpgrade()
    {
        int price = CalculateAttackUpgradePrice();
        if (playerStats.SpendCurrency(price))
        {
            playerStats.attackDamage += attackUpgradeAmount;
            attackUpgradePrice = (int)(attackUpgradePrice * 1.5f);
            return true;
        }
        return false;
    }

    public bool BuyDefenseUpgrade()
    {
        int price = CalculateDefenseUpgradePrice();
        if (playerStats.SpendCurrency(price))
        {
            playerStats.defense += defenseUpgradeAmount;
            defenseUpgradePrice = (int)(defenseUpgradePrice * 1.5f);
            return true;
        }
        return false;
    }

    public bool BuyMaxHealthUpgrade()
    {
        int price = CalculateMaxHealthUpgradePrice();
        if (playerStats.SpendCurrency(price))
        {
            playerStats.maxHealth += maxHealthUpgradeAmount;
            playerStats.currentHealth += maxHealthUpgradeAmount;
            maxHealthUpgradePrice = (int)(maxHealthUpgradePrice * 1.5f);
            return true;
        }
        return false;
    }

    public int CalculateHealthPotionPrice()
    {
        return healthPotionPrice;
    }

    public int CalculateAttackUpgradePrice()
    {
        return attackUpgradePrice;
    }

    public int CalculateDefenseUpgradePrice()
    {
        return defenseUpgradePrice;
    }

    public int CalculateMaxHealthUpgradePrice()
    {
        return maxHealthUpgradePrice;
    }

    public void PurchaseCurrencyPackSmall()
    {
        playerStats.AddCurrency(currencyPackSmallAmount);
    }

    public void PurchaseCurrencyPackMedium()
    {
        playerStats.AddCurrency(currencyPackMediumAmount);
    }

    public void PurchaseCurrencyPackLarge()
    {
        playerStats.AddCurrency(currencyPackLargeAmount);
    }
}

public class Enemy : MonoBehaviour
{
    public int health = 50;
    public int attackDamage = 15;
    public int currencyReward = 25;
    public int experienceReward = 50;

    PlayerStats playerStats;

    void Start()
    {
        playerStats = FindObjectOfType<PlayerStats>();
    }

    public void TakeDamage(int damage)
    {
        health -= damage;
        if (health <= 0)
        {
            Die();
        }
    }

    public void AttackPlayer()
    {
        if (playerStats != null)
        {
            playerStats.TakeDamage(attackDamage);
        }
    }

    void Die()
    {
        if (playerStats != null)
        {
            playerStats.AddCurrency(currencyReward);
            playerStats.AddExperience(experienceReward);
        }
        Destroy(gameObject);
    }
}

public class CombatSystem : MonoBehaviour
{
    public PlayerStats playerStats;

    void Start()
    {
        if (playerStats == null)
        {
            playerStats = FindObjectOfType<PlayerStats>();
        }
    }

    public void PlayerAttackEnemy(Enemy enemy)
    {
        if (enemy != null && playerStats != null)
        {
            int damage = CalculatePlayerDamage();
            enemy.TakeDamage(damage);
        }
    }

    public int CalculatePlayerDamage()
    {
        int baseDamage = playerStats.GetAttackDamage();
        int randomVariance = Random.Range(-2, 3);
        int totalDamage = baseDamage + randomVariance;
        if (totalDamage < 1)
        {
            totalDamage = 1;
        }
        return totalDamage;
    }

    public int CalculateCriticalDamage()
    {
        int baseDamage = playerStats.GetAttackDamage();
        return baseDamage * 2;
    }

    public bool RollCriticalHit()
    {
        float critChance = 0.15f;
        return Random.value < critChance;
    }

    public void ExecutePlayerAttack(Enemy enemy)
    {
        if (enemy != null && playerStats != null)
        {
            int damage;
            if (RollCriticalHit())
            {
                damage = CalculateCriticalDamage();
            }
            else
            {
                damage = CalculatePlayerDamage();
            }
            enemy.TakeDamage(damage);
        }
    }
}

public class UIManager : MonoBehaviour
{
