    {
        if (playerStats == null) return;

        GUILayout.BeginArea(new Rect(10, 10, 300, 400));
        
        GUILayout.Label("Health: " + playerStats.currentHealth + "/" + playerStats.maxHealth);
        GUILayout.Label("Currency: " + playerStats.currency);
        GUILayout.Label("Level: " + playerStats.level);
        GUILayout.Label("Experience: " + playerStats.experience + "/" + playerStats.experienceToNextLevel);
        GUILayout.Label("Attack: " + playerStats.attackDamage);
        GUILayout.Label("Defense: " + playerStats.defense);

        GUILayout.Space(20);
        GUILayout.Label("SHOP");

        if (shopSystem != null)
        {
            if (GUILayout.Button("Health Potion (" + shopSystem.CalculateHealthPotionPrice() + " gold)"))
            {
                shopSystem.BuyHealthPotion();
            }

            if (GUILayout.Button("Attack Upgrade (" + shopSystem.CalculateAttackUpgradePrice() + " gold)"))
            {
                shopSystem.BuyAttackUpgrade();
            }

            if (GUILayout.Button("Defense Upgrade (" + shopSystem.CalculateDefenseUpgradePrice() + " gold)"))
            {
                shopSystem.BuyDefenseUpgrade();
            }

            if (GUILayout.Button("Max Health Upgrade (" + shopSystem.CalculateMaxHealthUpgradePrice() + " gold)"))
            {
                shopSystem.BuyMaxHealthUpgrade();
            }

            GUILayout.Space(10);
            GUILayout.Label("IN-APP PURCHASES");

            if (GUILayout.Button("Small Currency Pack ($" + (shopSystem.currencyPackSmallPrice / 100f) + ")"))
            {
                shopSystem.PurchaseCurrencyPackSmall();
            }

            if (GUILayout.Button("Medium Currency Pack ($" + (shopSystem.currencyPackMediumPrice / 100f) + ")"))
            {
                shopSystem.PurchaseCurrencyPackMedium();
            }

            if (GUILayout.Button("Large Currency Pack ($" + (shopSystem.currencyPackLargePrice / 100f) + ")"))
            {
                shopSystem.PurchaseCurrencyPackLarge();
            }
        }

        GUILayout.EndArea();
    }
}